{"code":"import json, re
# Load stored query results
with open(var_call_Ow9DeaE9wDuFRl2s0DGnZKEU, 'r') as f:
    uc_records = json.load(f)
with open(var_call_extKKtbNjMJuiqaFvagK1ONA, 'r') as f:
    cited_records = json.load(f)

# Extract publication numbers for UNIV CALIFORNIA patents from Patents_info
uc_pubnums = set()
pubnum_regex = re.compile(r'([A-Z]{2}-[0-9]{4,}[A-Z0-9\-]*)')
for rec in uc_records:
    pi = rec.get('Patents_info','')
    matches = pubnum_regex.findall(pi)
    for m in matches:
        uc_pubnums.add(m.strip())

# Fallback: also look into title_localized maybe contains pub number? but skip
uc_pubnums = set([u for u in uc_pubnums if '-' in u])

# Parse cited_records citations and find those that cite any UC pubnum
citing_matches = []
for rec in cited_records:
    citation = rec.get('citation','')
    if not citation or citation.strip() == '[]':
        continue
    try:
        cited_list = json.loads(citation)
    except Exception:
        # try to fix single quotes
        try:
            cited_list = json.loads(citation.replace("'", '"'))
        except Exception:
            cited_list = []
    cited_pubnums = [c.get('publication_number','').strip() for c in cited_list if c.get('publication_number')]
    # check intersection
    inter = set(cited_pubnums) & uc_pubnums
    if inter:
        # extract assignee heuristically from Patents_info
        pi = rec.get('Patents_info','')
        assignee = None
        # patterns
        m = re.match(r'^\s*([^,\.]+?)\s+(?:holds|owns|has)\b', pi, re.IGNORECASE)
        if m:
            assignee = m.group(1).strip()
        if not assignee:
            m = re.search(r'is assigned to\s+([^,\.]+)', pi, re.IGNORECASE)
            if m:
                assignee = m.group(1).strip()
        if not assignee:
            m = re.search(r'is owned by\s+([^,\.]+)', pi, re.IGNORECASE)
            if m:
                assignee = m.group(1).strip()
        if not assignee:
            m = re.search(r'holds the .*?\), with publication number', pi, re.IGNORECASE)
            if m:
                # grab leading token
                m2 = re.match(r'^\s*([^,\.]+?)\s+', pi)
                if m2:
                    assignee = m2.group(1).strip()
        if not assignee:
            # fallback: take up to 'holds' or 'with' or first parenthesis
            m = re.split(r'\bholds\b|\bwith\b|\(|,', pi, 1)
            if m and m[0].strip():
                assignee = m[0].strip()
            else:
                assignee = pi.strip()
        # parse cpc codes
        cpc_field = rec.get('cpc','')
        codes = []
        try:
            cpc_list = json.loads(cpc_field)
        except Exception:
            try:
                cpc_list = json.loads(cpc_field.replace("'", '"'))
            except Exception:
                cpc_list = []
        for c in cpc_list:
            if isinstance(c, dict) and c.get('first'):
                code = c.get('code')
                if code:
                    codes.append(code.strip())
        # if no primary flagged, take first code if exists
        if not codes and cpc_list:
            for c in cpc_list:
                if isinstance(c, dict) and c.get('code'):
                    codes.append(c.get('code').strip())
                    break
        citing_matches.append({
            'rowid': rec.get('rowid'),
            'assignee_extracted': assignee,
            'codes': codes,
            'cited_uc_pubnums': list(inter),
            'Patents_info': rec.get('Patents_info')
        })

# Unique codes
unique_codes = sorted({code for rec in citing_matches for code in rec['codes'] if code})

output = {'uc_pubnums': sorted(list(uc_pubnums)), 'unique_codes': unique_codes, 'citing_matches': citing_matches}

print("__RESULT__:")
print(json.dumps(output))"}

{"code":"import json, re
with open(var_call_Ow9DeaE9wDuFRl2s0DGnZKEU, 'r') as f:
    uc_records = json.load(f)
with open(var_call_extKKtbNjMJuiqaFvagK1ONA, 'r') as f:
    cited_records = json.load(f)

# Build UC core digit set
def core_digits(s):
    if not s: return ''
    nums = re.findall(r"\d+", s)
    return ''.join(nums)

uc_cores = set()
for rec in uc_records:
    pi = rec.get('Patents_info','')
    # try to find publication numbers in pi
    pnums = re.findall(r'[A-Z]{2}-[0-9]{4,}[A-Z0-9\-]*|[A-Z]{2}\s*[0-9]{4,}[A-Z0-9\-]*|[A-Z]{2}-[0-9]{1,}', pi)
    # also find bare numbers
    pnums += re.findall(r'\bUS-?\d{4,}[A-Z0-9\-]*\b', pi)
    # fallback: any sequences like digits of length>=4
    if not pnums:
        pnums += re.findall(r'\d{4,,}', pi)
    for p in pnums:
        cd = core_digits(p)
        if cd:
            uc_cores.add(cd)
# Also scan citation fields in uc_records themselves
for rec in uc_records:
    citation = rec.get('citation','')
    try:
        cited_list = json.loads(citation) if citation else []
    except Exception:
        try:
            cited_list = json.loads(citation.replace("'", '"'))
        except Exception:
            cited_list = []
    for c in cited_list:
        pn = c.get('publication_number','')
        if pn:
            uc_cores.add(core_digits(pn))

# Now scan cited_records to find those that cite any UC core
matches = []
for rec in cited_records:
    citation = rec.get('citation','')
    if not citation or citation.strip()=='[]':
        continue
    try:
        cited_list = json.loads(citation)
    except Exception:
        try:
            cited_list = json.loads(citation.replace("'", '"'))
        except Exception:
            cited_list = []
    cited_pn = [c.get('publication_number','') for c in cited_list if c.get('publication_number')]
    cited_cores = [core_digits(p) for p in cited_pn]
    if any(core in uc_cores and core for core in cited_cores):
        # extract assignee
        pi = rec.get('Patents_info','')
        assignee = None
        # patterns
        m = re.search(r'^(.*?)\s+(?:holds|owns|has)\b', pi, re.IGNORECASE)
        if m:
            assignee = m.group(1).strip()
        if not assignee:
            m = re.search(r'is assigned to\s+([^,\.]+)', pi, re.IGNORECASE)
            if m:
                assignee = m.group(1).strip()
        if not assignee:
            m = re.search(r'is owned by\s+([^,\.]+)', pi, re.IGNORECASE)
            if m:
                assignee = m.group(1).strip()
        if not assignee:
            m = re.search(r'^(.*?)\s*\(', pi)
            if m:
                assignee = m.group(1).strip()
        if not assignee:
            # fallback to whole
            assignee = pi.strip()
        # normalize assignee: remove leading 'In US, ' or country prefixes
        assignee = re.sub(r'^In\s+\w+,\s*', '', assignee)
        assignee = assignee.strip()
        # parse cpc primary
        cpc_field = rec.get('cpc','')
        codes = []
        try:
            cpc_list = json.loads(cpc_field) if cpc_field else []
        except Exception:
            try:
                cpc_list = json.loads(cpc_field.replace("'", '"'))
            except Exception:
                cpc_list = []
        for c in cpc_list:
            if isinstance(c, dict) and c.get('first'):
                code = c.get('code')
                if code:
                    codes.append(code.strip())
        if not codes and cpc_list:
            for c in cpc_list:
                if isinstance(c, dict) and c.get('code'):
                    codes.append(c.get('code').strip())
                    break
        matches.append({'rowid': rec.get('rowid'), 'assignee': assignee, 'codes': codes, 'cited_pn': cited_pn})

# Aggregate by assignee: map assignee -> set of codes
agg = {}
for m in matches:
    a = m['assignee']
    if 'UNIV CALIFORNIA' in a.upper():
        continue
    if a not in agg:
        agg[a] = set()
    for code in m['codes']:
        if code:
            agg[a].add(code)

# prepare results
results = [{'assignee': a, 'codes': sorted(list(codes))} for a,codes in agg.items()]
unique_codes = sorted({c for _,codes in [(r['assignee'], r['codes']) for r in results] for c in codes})

out = {'results': results, 'unique_codes': unique_codes, 'num_matches': len(matches)}
print('__RESULT__:')
print(json.dumps(out))"}

